async (params, browser) => {
  // Open neighborhood page
  await browser.open(`https://www.zillow.com/homes/${params.location}_rb/`)

  // Wait for page to load
  await browser.waitForSelector('[class*=\'region\'], [class*=\'neighborhood\'], h1, [class*=\'home-values\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to neighborhood data
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract neighborhood info
  const neighborhood_data = await browser.evaluate(`const medianValueEl = document.querySelector('[class*="home-value"], [class*="median"], [class*="zestimate"]'); const walkScoreEl = document.querySelector('[class*="walk-score"], [class*="walkScore"]'); const transitScoreEl = document.querySelector('[class*="transit-score"], [class*="transitScore"]'); const bikeScoreEl = document.querySelector('[class*="bike-score"], [class*="bikeScore"]'); const schools = []; const schoolEls = document.querySelectorAll('[class*="school"] li, [class*="school-card"], [class*="nearby-school"]'); schoolEls.forEach(function(el) { const nameEl = el.querySelector('[class*="name"], a'); const ratingEl = el.querySelector('[class*="rating"], [class*="score"]'); const typeEl = el.querySelector('[class*="type"], [class*="level"]'); const distEl = el.querySelector('[class*="distance"]'); schools.push({ name: nameEl ? nameEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', type: typeEl ? typeEl.textContent.trim() : '', distance: distEl ? distEl.textContent.trim() : '' }); }); const demographics = {}; const demoEls = document.querySelectorAll('[class*="demographic"] li, [class*="population"], [class*="census"]'); demoEls.forEach(function(el) { const text = el.textContent.trim(); if (text.length < 200) { const parts = text.split(':'); if (parts.length === 2) { demographics[parts[0].trim()] = parts[1].trim(); } } }); const nearbyListings = []; const listingEls = document.querySelectorAll('[data-test="property-card"], [class*="property-card"]'); for (let i = 0; i < Math.min(listingEls.length, 5); i++) { const el = listingEls[i]; const addrEl = el.querySelector('address, [class*="address"]'); const priceEl = el.querySelector('[class*="price"]'); nearbyListings.push({ address: addrEl ? addrEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '' }); } return { location: '' + params.location + '', median_home_value: medianValueEl ? medianValueEl.textContent.trim() : '', walk_score: walkScoreEl ? walkScoreEl.textContent.trim() : '', transit_score: transitScoreEl ? transitScoreEl.textContent.trim() : '', bike_score: bikeScoreEl ? bikeScoreEl.textContent.trim() : '', schools: schools.slice(0, 10), demographics: demographics, nearby_listings: nearbyListings, url: window.location.href }`)

  return neighborhood_data
}
